     7→
     8→export interface TicketItem {
     9→  nombre: string;
    10→  cantidad: number;
    11→  precio: number;
    12→  observaciones?: string;
    13→  emoji?: string;
    14→}
    15→
    16→export interface TicketPedido {
    17→  id: number;
    18→  mesa: string;
    19→  items: TicketItem[];
    20→  total: number;
    21→  notas?: string;
    22→  mesero?: string;
    23→  fecha: Date;
    24→  estado?: string;
    25→}
    26→
    27→export interface TicketFactura extends TicketPedido {
    28→  pagos: { metodo: string; monto: number }[];
    29→  propina: number;
    30→  totalConPropina: number;
    31→  cambio: number;
    32→  metodoPago: string;
    33→  cobradoPor?: string;
    34→}
    35→
    36→const LINE = 30; // 58mm thermal = ~30 chars with safe margin
    37→
    38→function padLine(left: string, right: string, width = LINE): string {
    39→  const spaces = width - left.length - right.length;
    40→  return left + " ".repeat(Math.max(1, spaces)) + right;
    41→}
    42→
    43→function center(str: string, width = LINE): string {
    44→  const pad = Math.max(0, Math.floor((width - str.length) / 2));
    45→  return " ".repeat(pad) + str;
    46→}
    47→
    48→function divider(char = "-", width = LINE): string {
    49→  return char.repeat(width);
    50→}
    51→
    52→function fmtPrice(n: number): string {
    53→  return "$" + n.toLocaleString("es-CO");
    54→}
    55→
    56→function fmtItemName(i: TicketItem): string {
    57→  const name = `${i.cantidad}x ${i.nombre}`;
    58→  const max = LINE - 8;
    59→  return name.length > max ? name.substring(0, max - 1) + "." : name;
    60→}
    61→
    62→export function buildComandaTicket(p: TicketPedido): string {
    63→  const hora = p.fecha.toLocaleTimeString("es-CO", { hour: "2-digit", minute: "2-digit" });
    64→  const fecha = p.fecha.toLocaleDateString("es-CO");
    65→
    66→  const itemsTxt = p.items.map((i) => {
    67→    const display = fmtItemName(i);
    68→    const price = fmtPrice(i.precio * i.cantidad);
    69→    return padLine(display, price) + (i.observaciones ? `\n  * ${i.observaciones.substring(0, LINE - 4)}` : "");
    70→  }).join("\n");
    71→
    72→  return [
    73→    divider("="),
    74→    center("TIAMO BURGER"),
    75→    center("COMANDA COCINA"),
    76→    divider("="),
    77→    center(`#${String(p.id).padStart(4, "0")}`),
    78→    divider("-"),
    79→    `Mesa:${p.mesa}  ${hora} ${fecha}`,
    80→    divider("-"),
    81→    itemsTxt,
    82→    divider("-"),
    83→    padLine("TOTAL:", fmtPrice(p.total)),
    84→    divider("="),
    85→    p.notas ? `Notas:${p.notas}` : "",
    86→    `Mesero:${p.mesero ?? "-"}`,
    87→    divider("="),
    88→  ].filter(Boolean).join("\n") + "\n";
    89→}
