    34→// Latin-1 fallback map para caracteres comunes en español
    35→function toLatin1(str: string): Buffer {
    36→  const bytes: number[] = [];
    37→  for (let i = 0; i < str.length; i++) {
    38→    const code = str.charCodeAt(i);
    39→    if (code < 128) {
    40→      bytes.push(code);
    41→    } else if (code === 241) { bytes.push(0xf1); }      // ñ
    42→    else if (code === 209) { bytes.push(0xd1); }        // Ñ
    43→    else if (code === 225) { bytes.push(0xe1); }        // á
    44→    else if (code === 233) { bytes.push(0xe9); }        // é
    45→    else if (code === 237) { bytes.push(0xed); }        // í
    46→    else if (code === 243) { bytes.push(0xf3); }        // ó
    47→    else if (code === 250) { bytes.push(0xfa); }        // ú
    48→    else if (code === 193) { bytes.push(0xc1); }        // Á
    49→    else if (code === 201) { bytes.push(0xc9); }        // É
    50→    else if (code === 205) { bytes.push(0xcd); }        // Í
    51→    else if (code === 211) { bytes.push(0xd3); }        // Ó
    52→    else if (code === 218) { bytes.push(0xda); }        // Ú
    53→    else if (code === 252) { bytes.push(0xfc); }        // ü
    54→    else if (code === 220) { bytes.push(0xdc); }        // Ü
    55→    else if (code === 161) { bytes.push(0xa1); }        // ¡
    56→    else if (code === 191) { bytes.push(0xbf); }        // ¿
    57→    else if (code === 176) { bytes.push(0xb0); }        // °
    58→    else if (code === 8212) { bytes.push(0x2d); }       // — -> -
    59→    else if (code === 8211) { bytes.push(0x2d); }       // – -> -
    60→    else if (code === 8230) { bytes.push(0x2e, 0x2e, 0x2e); } // … -> ...
    61→    else if (code >= 0x80 && code <= 0xff) { bytes.push(code); }
    62→    else { bytes.push(0x3f); } // '?' for unknown chars
    63→  }
    64→  return Buffer.from(bytes);
    65→}
