    69→function padLine(left: string, right: string, width = LINE_CHARS): string {
    70→  const spaces = width - left.length - right.length;
    71→  return left + " ".repeat(Math.max(1, spaces)) + right;
    72→}
    73→
    74→function center(str: string, width = LINE_CHARS): string {
    75→  const pad = Math.max(0, Math.floor((width - str.length) / 2));
    76→  return " ".repeat(pad) + str;
    77→}
