const handleLiberarMesa = async (mesaNum: string) => {
  setLiberandoMesa(true);
  try {
    const base = import.meta.env.BASE_URL?.replace(/\/$/, "") ?? "";
    const r = await fetch(`${base}/api/mesas/${encodeURIComponent(mesaNum)}`, {
      method: "PATCH",
      headers: { "Content-Type": "application/json" },
      credentials: "include",
      body: JSON.stringify({ estado: "libre", personas: 0 }),
    });
    if (!r.ok) throw new Error("Error al liberar mesa");
    queryClient.invalidateQueries({ queryKey: getGetMesasQueryKey() });
    setMesaAcciones(null);
    toast({ title: `Mesa ${mesaNum} liberada`, description: "La mesa quedó disponible" });
  } catch {
    toast({ title: "Error", description: "No se pudo liberar la mesa", variant: "destructive" });
  } finally {
    setLiberandoMesa(false);
  }
};

