      precio: (it.precio ?? 0) as number,
      subtotal: ((it.precio ?? 0) * (it.cantidad ?? 1)) as number,
      pedidoId: p.id as number,
    }));
  });
  const totalProductos = allProductos.reduce((s, i) => s + i.subtotal, 0);

