   302→// Convert text ticket to ESC/POS binary for network printing
   303→export function textToEscPos(text: string): Buffer {
   304→  const parts: (Buffer | string)[] = [
   305→    CMD.init,
   306→    CMD.codePage(16),
   307→    CMD.alignLeft,
   308→  ];
   309→
   310→  const lines = text.split("\n");
   311→  for (const line of lines) {
   312→    const trimmed = line.trim();
   313→    if (!trimmed) {
   314→      parts.push("\n");
   315→      continue;
   316→    }
   317→    // Detect centered lines
   318→    if (trimmed.startsWith("TIAMO") || trimmed.startsWith("COMANDA") || trimmed.startsWith("FACTURA") || trimmed.startsWith("TICKET") || trimmed.startsWith("Gracias") || trimmed.startsWith("www.")) {
   319→      parts.push(CMD.alignCenter, trimmed, "\n", CMD.alignLeft);
   320→    } else if (trimmed.startsWith("===") || trimmed.startsWith("---")) {
   321→      parts.push(CMD.alignCenter, trimmed, "\n", CMD.alignLeft);
   322→    } else {
   323→      parts.push(trimmed, "\n");
   324→    }
   325→  }
   326→
   327→  parts.push(CMD.feedLines(3), CMD.cutPartial);
   328→  return concat(...parts);
   329→}
