                    </div>
                    <div>
                      <div className={`text-xl font-black ${haySesion ? "text-emerald-400 neon-emerald" : "text-zinc-400"}`}>
                        {isSesionLoading ? "..." : haySesion ? "CAJA ABIERTA" : "CAJA CERRADA"}
                      </div>
                      {haySesion && sesionActiva && (
