                          ["Efectivo contado", formatPrice(resultadoCierre.efectivoContado)],
                          ["Transferencias", formatPrice(resultadoCierre.totalTransferencia)],
                          ["Propinas", formatPrice(resultadoCierre.totalPropinas)],
