                          className="bg-white/5 border-white/10 text-white font-mono text-lg h-12"
                          placeholder="$0"
                        />
                      </div>
                      <div>
                        <label className="text-xs font-bold text-zinc-500 uppercase tracking-wider block mb-1.5">Observaciones (opcional)</label>
