import { useState, useEffect } from "react";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { useCobrarPedido, getGetPedidosQueryKey, getGetMesasQueryKey } from "@workspace/api-client-react";
import { useQueryClient } from "@tanstack/react-query";
import { useToast } from "@/hooks/use-toast";
import { formatPrice } from "@/lib/constants";
import { Banknote, CreditCard, Split, Check, AlertCircle, Printer, Receipt, Usb, DoorOpen } from "lucide-react";
import { useLocalPrinter } from "@/hooks/use-local-printer";

type MetodoPago = "efectivo" | "transferencia" | "mixto";

interface CobrarModalProps {
  pedido: {
    id: number;
    mesa: string;
    total: number;
    items?: any[];
  } | null;
  open: boolean;
  onClose: () => void;
}

const PROPINAS_SUGERIDAS = [
  { label: "Sin propina", pct: 0 },
  { label: "5%", pct: 5 },
  { label: "10%", pct: 10 },
  { label: "15%", pct: 15 },
];

const BILLETES_COMUNES = [1000, 2000, 5000, 10000, 20000, 50000, 100000];

export function CobrarModal({ pedido, open, onClose }: CobrarModalProps) {
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const cobrarMutation = useCobrarPedido();
  const localPrinter = useLocalPrinter();

  const [metodo, setMetodo] = useState<MetodoPago>("efectivo");
  const [propinaPct, setPropinaPct] = useState<number | null>(0);
  const [propinaCustom, setPropinaCustom] = useState("");
  const [efectivoStr, setEfectivoStr] = useState("");
  const [transferenciaStr, setTransferenciaStr] = useState("");
  const [exito, setExito] = useState(false);
  const [cambioFinal, setCambioFinal] = useState(0);
  const [facturaTicket, setFacturaTicket] = useState<string | null>(null);
  const [facturaImpresa, setFacturaImpresa] = useState(false);
  const [pedidoIdCobrado, setPedidoIdCobrado] = useState<number | null>(null);

  const total = pedido?.total ?? 0;

  const propina = (() => {
    if (propinaPct !== null) return Math.round(total * propinaPct / 100);
    const v = parseInt(propinaCustom.replace(/\D/g, "") || "0");
    return isNaN(v) ? 0 : v;
  })();

  const totalConPropina = total + propina;

  const efectivo = parseInt(efectivoStr.replace(/\D/g, "") || "0") || 0;
  const transferencia = parseInt(transferenciaStr.replace(/\D/g, "") || "0") || 0;

  const montoPagado = metodo === "efectivo" ? efectivo
    : metodo === "transferencia" ? transferencia
    : efectivo + transferencia;

  const cambio = metodo === "efectivo" ? Math.max(0, efectivo - totalConPropina) : 0;
  const faltante = Math.max(0, totalConPropina - montoPagado);

  useEffect(() => {
    if (!open) {
      setMetodo("efectivo");
      setPropinaPct(0);
      setPropinaCustom("");
      setEfectivoStr("");
      setTransferenciaStr("");
      setExito(false);
      setCambioFinal(0);
      setFacturaTicket(null);
      setFacturaImpresa(false);
      setPedidoIdCobrado(null);
    }
  }, [open]);

  const formatInput = (val: string) => {
    const num = val.replace(/\D/g, "");
    return num ? parseInt(num).toLocaleString("es-CO") : "";
  };

  const cerrarMesaAutomatico = async (mesaNum: string) => {
    try {
      const base = import.meta.env.BASE_URL?.replace(/\/$/, "") ?? "";
      await fetch(`${base}/api/mesas/${encodeURIComponent(mesaNum)}/cerrar`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        credentials: "include",
        body: JSON.stringify({}),
      });
      queryClient.invalidateQueries({ queryKey: getGetMesasQueryKey() });
    } catch {
      // silencioso — la mesa se puede cerrar manualmente
    }
  };

  const abrirFacturaHtml = (id: number, autoPrint = true) => {
    const url = `${window.location.origin}/api/pedidos/${id}/factura${autoPrint ? "?autoprint=1" : ""}`;
    const win = window.open(url, "_blank");
    if (!win) {
      toast({ title: "Permita ventanas emergentes para imprimir la factura", variant: "destructive" });
    }
  };

  const imprimirFacturaTicket = (ticket: string, autoPrint = true) => {
    const win = window.open("", "_blank", "width=420,height=700");
    if (!win) {
      toast({ title: "Permita ventanas emergentes", variant: "destructive" });
      return;
    }
    win.document.write(`<!DOCTYPE html><html><head><meta charset="UTF-8"><title>Factura TIAMO BURGER</title><style>
      *{margin:0;padding:0;box-sizing:border-box}body{font-family:'Courier New',monospace;font-size:12px;width:80mm;padding:8px;background:#fff;color:#000}
      pre{white-space:pre;font-size:11px;line-height:1.3}
      @media print{@page{margin:0}body{padding:4px}}
    </style></head><body>
      <pre>${ticket.replace(/</g, "&lt;")}</pre>
      <script>window.onload=()=>{${autoPrint ? "setTimeout(()=>{window.print();},300);" : ""}}</script>
    </body></html>`);
    win.document.close();
  };

  const handleCobrar = async () => {
    if (!pedido) return;
    if (faltante > 0 && metodo !== "transferencia") {
      toast({ title: "Monto insuficiente", description: `Faltan ${formatPrice(faltante)}`, variant: "destructive" });
      return;
    }

    const pagos = metodo === "efectivo"
      ? [{ metodo: "efectivo" as const, monto: Math.min(efectivo, totalConPropina) }]
      : metodo === "transferencia"
      ? [{ metodo: "transferencia" as const, monto: totalConPropina }]
      : [
          ...(efectivo > 0 ? [{ metodo: "efectivo" as const, monto: efectivo }] : []),
          ...(transferencia > 0 ? [{ metodo: "transferencia" as const, monto: transferencia }] : []),
        ];

    try {
      const r = await cobrarMutation.mutateAsync({ id: pedido.id, data: { pagos, propina, nota: "Cobrado en caja" } });

      const cambioCalculado = r.cambio ?? 0;
      const ticket = (r as any).facturaTicket ?? null;
      const pedidoId = pedido.id;

      setCambioFinal(cambioCalculado);
      setFacturaTicket(ticket);
      setPedidoIdCobrado(pedidoId);
      setExito(true);

      queryClient.invalidateQueries({ queryKey: getGetPedidosQueryKey() });

      // Cerrar mesa automáticamente
      await cerrarMesaAutomatico(pedido.mesa);

      // Abrir factura HTML automáticamente para imprimir
      abrirFacturaHtml(pedidoId, true);
      setFacturaImpresa(true);

      // Imprimir también en impresora física si está conectada
      if (ticket) {
        localPrinter.print(ticket).then((res) => {
          if (res.ok) toast({ title: "Factura impresa en impresora física" });
        });
      }

      toast({
        title: "¡Mesa cobrada y liberada!",
        description: `Mesa ${pedido.mesa} — ${formatPrice(totalConPropina)}${cambioCalculado > 0 ? ` · Cambio: ${formatPrice(cambioCalculado)}` : ""}`,
      });
    } catch (e: any) {
      toast({ title: "Error al cobrar", description: e?.message ?? "Error desconocido", variant: "destructive" });
    }
  };

  if (!pedido) return null;

  const puedeConfirmar = metodo === "transferencia"
    ? true
    : metodo === "efectivo"
    ? efectivo >= totalConPropina
    : (efectivo + transferencia) >= totalConPropina;

  return (
    <Dialog open={open} onOpenChange={(v) => !v && onClose()}>
      <DialogContent className={`${exito ? "sm:max-w-md" : "sm:max-w-lg"} bg-[#111] border-white/10 text-white p-0 overflow-hidden`}>
        <DialogHeader className="px-6 pt-6 pb-0">
          <DialogTitle className="text-xl font-black flex items-center gap-2">
            <Banknote className="w-5 h-5" style={{ color: "#FF2D2D" }} />
            {exito ? `Mesa ${pedido.mesa} — Cobrada` : `Cobrar Mesa ${pedido.mesa}`}
          </DialogTitle>
        </DialogHeader>

        {/* ════════ ESTADO: ÉXITO ════════ */}
        {exito ? (
          <div className="flex flex-col px-6 pb-6 pt-4 gap-4">
            {/* Banner de éxito con cambio */}
            <div className="rounded-2xl border border-emerald-500/25 bg-emerald-500/6 p-4 flex items-center gap-4">
              <div className="w-12 h-12 rounded-full bg-emerald-500/20 flex items-center justify-center shrink-0">
                <Check className="w-6 h-6 text-emerald-400" />
              </div>
              <div className="flex-1">
                <div className="text-base font-black text-white">¡Pago registrado!</div>
                <div className="text-xs text-zinc-500 mt-0.5">Mesa {pedido.mesa} cobrada y liberada</div>
              </div>
              {cambioFinal > 0 && (
                <div className="text-right shrink-0">
                  <div className="text-[10px] text-emerald-400/70 font-bold uppercase tracking-wider">Dar vuelto</div>
                  <div className="text-2xl font-black font-mono text-emerald-400">{formatPrice(cambioFinal)}</div>
                </div>
              )}
            </div>

            {/* Resumen del cobro */}
            <div className="rounded-xl border border-white/5 p-4 space-y-2 bg-white/2 text-sm">
              <div className="flex justify-between">
                <span className="text-zinc-500">Subtotal</span>
                <span className="font-mono font-bold">{formatPrice(total)}</span>
              </div>
              {propina > 0 && (
                <div className="flex justify-between">
                  <span className="text-zinc-500">Propina</span>
                  <span className="font-mono font-bold text-emerald-400">+{formatPrice(propina)}</span>
                </div>
              )}
              <div className="flex justify-between border-t border-white/5 pt-2">
                <span className="font-bold text-white">Total cobrado</span>
                <span className="font-black font-mono text-lg" style={{ color: "#FF2D2D" }}>{formatPrice(totalConPropina)}</span>
              </div>
            </div>

            {/* Opciones de impresión */}
            <div className="space-y-2">
              <div className="text-[10px] font-bold text-zinc-600 uppercase tracking-wider text-center">Factura abierta automáticamente · Reimprimir si es necesario</div>
              <div className="grid grid-cols-2 gap-2">
                <Button
                  variant="outline"
                  className="border-white/10 hover:bg-white/5 text-white text-xs h-10 gap-1.5"
                  onClick={() => pedidoIdCobrado && abrirFacturaHtml(pedidoIdCobrado, true)}
                >
                  <Printer className="w-3.5 h-3.5" />
                  Reimprimir Factura
                </Button>
                <Button
                  variant="outline"
                  className="border-white/10 hover:bg-white/5 text-white text-xs h-10 gap-1.5"
                  onClick={async () => {
                    if (!facturaTicket) return;
                    const res = await localPrinter.print(facturaTicket);
                    if (res.ok) toast({ title: "Factura enviada a impresora física" });
                    else toast({ title: "Sin impresora física", description: res.mensaje, variant: "destructive" });
                  }}
                  disabled={localPrinter.state.isPrinting || !facturaTicket}
                >
                  <Usb className="w-3.5 h-3.5" />
                  Impresora Física
                </Button>
              </div>
            </div>

            <Button
              className="w-full h-12 font-black text-base gap-2"
              style={{ background: "linear-gradient(135deg,#22c55e,#16a34a)" }}
              onClick={onClose}
            >
              <DoorOpen className="w-5 h-5" />
              Volver a Mesas
            </Button>
          </div>

        ) : (
        /* ════════ ESTADO: FORMULARIO DE PAGO ════════ */
          <div className="px-6 pb-6 pt-4 space-y-5">
            {/* Total */}
            <div className="flex justify-between items-center py-3 px-4 rounded-xl border border-white/8 bg-white/3">
              <span className="text-zinc-400 font-semibold text-sm">Total pedido</span>
              <span className="text-2xl font-black font-mono text-white">{formatPrice(total)}</span>
            </div>

            {/* Propina */}
            <div>
              <div className="text-xs font-bold text-zinc-500 uppercase tracking-wider mb-2">Propina</div>
              <div className="grid grid-cols-4 gap-2 mb-2">
                {PROPINAS_SUGERIDAS.map((p) => (
                  <button
                    key={p.label}
                    onClick={() => { setPropinaPct(p.pct); setPropinaCustom(""); }}
                    className={`h-9 rounded-lg text-xs font-bold border transition-all ${
                      propinaPct === p.pct && !propinaCustom
                        ? "border-red-500/50 bg-red-500/10 text-red-400"
                        : "border-white/10 bg-white/3 text-zinc-400 hover:border-white/20"
                    }`}
                  >
                    {p.label}
                  </button>
                ))}
              </div>
              <Input
                placeholder="Propina manual ($)"
                value={propinaCustom}
                onChange={(e) => { setPropinaCustom(formatInput(e.target.value)); setPropinaPct(null); }}
                className="bg-white/3 border-white/10 text-white placeholder:text-zinc-600 h-9"
              />
              {propina > 0 && (
                <div className="text-xs text-emerald-400 mt-1.5 font-semibold">+ Propina: {formatPrice(propina)}</div>
              )}
            </div>

            {/* Método de pago */}
            <div>
              <div className="text-xs font-bold text-zinc-500 uppercase tracking-wider mb-2">Forma de pago</div>
              <div className="grid grid-cols-3 gap-2">
                {[
                  { key: "efectivo", label: "Efectivo", icon: Banknote },
                  { key: "transferencia", label: "Transferencia", icon: CreditCard },
                  { key: "mixto", label: "Mixto", icon: Split },
                ].map(({ key, label, icon: Icon }) => (
                  <button
                    key={key}
                    onClick={() => setMetodo(key as MetodoPago)}
                    className={`flex flex-col items-center gap-1.5 py-3 rounded-xl border text-xs font-bold transition-all ${
                      metodo === key
                        ? "border-red-500/50 bg-red-500/10 text-red-400"
                        : "border-white/10 bg-white/3 text-zinc-400 hover:border-white/20"
                    }`}
                  >
                    <Icon className="w-4 h-4" />
                    {label}
                  </button>
                ))}
              </div>
            </div>

            {/* Efectivo recibido */}
            {(metodo === "efectivo" || metodo === "mixto") && (
              <div>
                <div className="text-xs font-bold text-zinc-500 uppercase tracking-wider mb-2">Efectivo recibido</div>
                <Input
                  placeholder="Monto en efectivo"
                  value={efectivoStr}
                  onChange={(e) => setEfectivoStr(formatInput(e.target.value))}
                  className="bg-white/3 border-white/10 text-white placeholder:text-zinc-600 font-mono text-base h-11"
                  autoFocus={metodo === "efectivo"}
                />
                {metodo === "efectivo" && (
                  <div className="flex flex-wrap gap-2 mt-2">
                    {BILLETES_COMUNES.filter((b) => b >= totalConPropina && b <= totalConPropina * 3).slice(0, 5).map((b) => (
                      <button
                        key={b}
                        onClick={() => setEfectivoStr(b.toLocaleString("es-CO"))}
                        className="px-3 py-1.5 rounded-lg bg-white/5 border border-white/10 text-xs font-bold text-zinc-300 hover:bg-white/10 transition-colors"
                      >
                        {formatPrice(b)}
                      </button>
                    ))}
                  </div>
                )}
              </div>
            )}

            {(metodo === "transferencia" || metodo === "mixto") && (
              <div>
                <div className="text-xs font-bold text-zinc-500 uppercase tracking-wider mb-2">
                  {metodo === "mixto" ? "Transferencia (complemento)" : "Monto por transferencia"}
                </div>
                <Input
                  placeholder="Monto transferencia"
                  value={transferenciaStr}
                  onChange={(e) => setTransferenciaStr(formatInput(e.target.value))}
                  className="bg-white/3 border-white/10 text-white placeholder:text-zinc-600 font-mono text-base h-11"
                  autoFocus={metodo === "transferencia"}
                />
              </div>
            )}

            {/* Resumen con cambio en tiempo real */}
            <div className="rounded-xl border border-white/8 p-4 space-y-2 bg-white/2">
              <div className="flex justify-between text-sm">
                <span className="text-zinc-500">Subtotal</span>
                <span className="font-mono font-bold">{formatPrice(total)}</span>
              </div>
              {propina > 0 && (
                <div className="flex justify-between text-sm">
                  <span className="text-zinc-500">Propina</span>
                  <span className="font-mono font-bold text-emerald-400">+{formatPrice(propina)}</span>
                </div>
              )}
              <div className="border-t border-white/8 pt-2 flex justify-between items-center">
                <span className="font-bold text-white">Total a cobrar</span>
                <span className="font-black text-2xl font-mono" style={{ color: "#FF2D2D" }}>{formatPrice(totalConPropina)}</span>
              </div>

              {/* Cambio en vivo */}
              {metodo === "efectivo" && efectivo >= totalConPropina && cambio >= 0 && (
                <div className="flex justify-between items-center pt-1 mt-1 border-t border-emerald-500/20 bg-emerald-500/5 -mx-4 px-4 py-2 rounded-b-xl">
                  <span className="font-black text-emerald-400 text-sm">💵 Vuelto al cliente</span>
                  <span className="font-black font-mono text-xl text-emerald-400">{formatPrice(cambio)}</span>
                </div>
              )}
              {faltante > 0 && montoPagado > 0 && (
                <div className="flex items-center gap-2 text-red-400 text-xs font-bold pt-1">
                  <AlertCircle className="w-3.5 h-3.5" />
                  Faltan {formatPrice(faltante)}
                </div>
              )}
            </div>

            <Button
              onClick={handleCobrar}
              disabled={cobrarMutation.isPending || !puedeConfirmar}
              className="w-full h-14 font-black text-lg gap-2"
              style={{ background: puedeConfirmar ? "linear-gradient(135deg,#FF2D2D 0%,#CC0000 100%)" : undefined }}
            >
              {cobrarMutation.isPending
                ? <><div className="w-5 h-5 animate-spin rounded-full border-2 border-white/30 border-t-white" />Procesando...</>
                : `Cobrar ${formatPrice(totalConPropina)}`}
            </Button>
          </div>
        )}
      </DialogContent>
    </Dialog>
  );
}

