    19→function useTimer(startedAt?: string | null) {
    20→  const [elapsed, setElapsed] = useState(0);
    21→  useEffect(() => {
    22→    if (!startedAt) return;
    23→    const start = new Date(startedAt).getTime();
    24→    const tick = () => setElapsed(Math.floor((Date.now() - start) / 1000));
    25→    tick();
    26→    const t = setInterval(tick, 15000);
    27→    return () => clearInterval(t);
    28→  }, [startedAt]);
    29→  if (!startedAt) return null;
    30→  const m = Math.floor(elapsed / 60);
    31→  const h = Math.floor(m / 60);
    32→  if (h > 0) return `${h}h ${m % 60}m`;
    33→  return `${m}m`;
    34→}
