        const propinaNueva = (ultimoPedido.propina ?? 0) + propina;
        await db.update(pedidosTable)
          .set({ propina: propinaNueva })
          .where(eq(pedidosTable.id, ultimoPedido.id));
        broadcast("pedido_actualizado", { id: ultimoPedido.id });
      }
    }

