   305→// Convert text ticket to ESC/POS binary for network printing
   306→export function textToEscPos(text: string): Buffer {
   307→  const parts: (Buffer | string)[] = [
   308→    CMD.init,
   309→    CMD.codePage(16),
   310→    CMD.alignLeft,
   311→  ];
   312→
   313→  const lines = text.split("\n");
   314→  for (const line of lines) {
   315→    const trimmed = line.trim();
   316→    if (!trimmed) {
   317→      parts.push("\n");
   318→      continue;
   319→    }
   320→    // Detect centered lines
   321→    if (trimmed.startsWith("TIAMO") || trimmed.startsWith("COMANDA") || trimmed.startsWith("FACTURA") || trimmed.startsWith("TICKET") || trimmed.startsWith("Gracias") || trimmed.startsWith("www.")) {
   322→      parts.push(CMD.alignCenter, trimmed, "\n", CMD.alignLeft);
   323→    } else if (trimmed.startsWith("===") || trimmed.startsWith("---")) {
   324→      parts.push(CMD.alignCenter, trimmed, "\n", CMD.alignLeft);
   325→    } else {
   326→      parts.push(trimmed, "\n");
   327→    }
   328→  }
   329→
   330→  parts.push(CMD.feedLines(3), CMD.cutPartial);
   331→  return concat(...parts);
   332→}
